 70→// Enqueue styles and scripts
 71→function hone_landing_enqueue_assets() {
 72→    global $class_names;
 73→
 74→    $theme_version = wp_get_theme()->get('Version');
 75→    $theme_uri = get_template_directory_uri();
 76→
 77→    // Always load main.min.css - contains all common styles (reset, settings, parts)
 78→    wp_enqueue_style(
 79→        'hone-main-style',
 80→        $theme_uri . '/static/css/main.min.css',
 81→        array(),
 82→        $theme_version
 83→    );
 84→
 85→    // Early return if no class_names set
 86→    if (empty($class_names) || !is_array($class_names)) {
 87→        return;
 88→    }
 89→
 90→    // Check if this template has page-specific styles
 91→    $matches = array_intersect($class_names, HONE_PAGE_TEMPLATES);
 92→
 93→    // Load all matching page-specific styles in order
 94→    // This allows for layered styles (e.g., base 'mens-hrt-aol' + specific 'mens-hrt-aol-forbes')
 95→    if (!empty($matches)) {
 96→        $dependencies = array('hone-main-style'); // First match depends on main styles
 97→        
 98→        foreach ($matches as $matched_class) {
 99→            $css_file = get_template_directory() . '/static/css/pages/' . $matched_class . '.css';
100→            if (file_exists($css_file)) {
101→                wp_enqueue_style(
102→                    'hone-page-' . $matched_class,
103→                    $theme_uri . '/static/css/pages/' . $matched_class . '.css',
104→                    $dependencies,
105→                    $theme_version,
106→                    'all'
107→                );
108→                // Make next stylesheet depend on this one to maintain load order
109→                $dependencies = array('hone-page-' . $matched_class);
110→            }
111→        }
112→    }
113→    
114→    // Enqueue main JavaScript (always loaded - contains trackQuizEvent)
115→    wp_enqueue_script(
116→        'hone-main-script',
117→        $theme_uri . '/static/js/dist/combined.js',
118→        array(),
119→        $theme_version,
120→        true
121→    );
122→}
123→add_action('wp_enqueue_scripts', 'hone_landing_enqueue_assets');
